def compute_score():
    # Find the only added slide
    if len(ppt_diff.added_slides) != 1:
        return ("Cannot check position because the number of added slides is not 1.", 0.0)
    added_slide = ppt_diff.added_slides[0]
    # In the modified presentation, slide 5 should be the new slide
    from pptx import Presentation
    prs = Presentation(modified_ppt_path)
    slides = list(prs.slides)
    if len(slides) < 5:
        return ("Modified presentation has fewer than 5 slides.", 0.0)
    slide5 = slides[4]  # 0-based index
    # Try to match slide5 with added_slide by title or element count
    try:
        title = None
        for shape in slide5.shapes:
            if shape.has_text_frame and shape.text_frame.text.strip():
                title = shape.text_frame.text.strip()
                break
        if title and title.strip().lower() == (added_slide.title or '').strip().lower():
            return ("Slide was correctly inserted after slide 4.", 1.0)
    except Exception:
        pass
    # Fallback: match by element count or assume the structure matches
    # If slide ids are stable, could match by slide_id
    # If all else fails, check if slide5 is not present in original
    from pptx import Presentation as OrigPresentation
    orig_prs = OrigPresentation(original_ppt_path)
    orig_slides = list(orig_prs.slides)
    orig_titles = set()
    for s in orig_slides:
        for shape in s.shapes:
            if shape.has_text_frame and shape.text_frame.text.strip():
                orig_titles.add(shape.text_frame.text.strip().lower())
    if title and title.strip().lower() not in orig_titles:
        return ("Slide inserted after slide 4 and is new.", 1.0)
    return ("New slide does not appear after slide 4.", 0.0)

